@if($attendance->count())<div class="table-responsive"><table class="table table-striped table-hover"><thead><tr><th>Date</th><th>Employee</th><th>Check In</th><th>Check Out</th><th>Working Hours</th><th>Status</th></tr></thead><tbody>@foreach($attendance as $record)<tr><td>{{ $record->attendance_date?->format('d M Y') }}</td><td>{{ $record->user?->name ?? '-' }}</td><td>{{ $record->check_in ?? '-' }}</td><td>{{ $record->check_out ?? '-' }}</td><td>{{ $record->working_hours ?? '-' }}</td><td><span class="badge bg-{{ $record->status_badge ?? 'secondary' }}">{{ $record->display_status ?? $record->status }}</span></td></tr>@endforeach</tbody></table></div><div class="mt-3">{{ $attendance->withQueryString()->links() }}</div>@else<div class="text-center py-5"><i class="fas fa-chart-bar fa-3x text-muted mb-3"></i><h4>No Attendance Report Found</h4></div>@endif
